import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Additional tests for SpacingAroundColonRule specifically for annotation use-site targets.
 * https://github.com/pinterest/ktlint/issues/2093
 */
class SpacingAroundColonInAnnotationRuleTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Nested
    inner class `Given a file annotation with use-site target` {
        @Test
        fun `Given a file annotation with no spacing around colon then do not report a violation`() {
            val code =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a file annotation with space before colon then report a violation and fix it`() {
            val code =
                """
                @file :JvmName("Foo")
                """.trimIndent()
            val formattedCode =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code)
                .hasLintViolation(1, 6, "Unexpected spacing before \":\"")
                .isFormattedAs(formattedCode)
